INSERT INTO features (id, slug, name, feature_type, category, status, visibility, officiality, public_description) VALUES
('seed_001', 'volker', 'Volker', 'point', 'Neighborhoods', 'open', 'public', 'official', 'West anchor near Westport and the Plaza; strong handoff into Brush Creek.'),
('seed_002', 'blue-hills', 'Blue Hills', 'point', 'Neighborhoods', 'open', 'public', 'official', 'Mid-city ladder neighborhood between central KC and the east-side river world.'),
('seed_003', 'vineyard', 'Vineyard', 'point', 'Neighborhoods', 'open', 'public', 'official', 'Useful middle connector when stitching Brush Creek toward Blue River and Swope.'),
('seed_004', 'east-blue-valley', 'East Blue Valley', 'point', 'Neighborhoods', 'open', 'public', 'official', 'Industrial-river corridor zone near Leeds and stadium-facing approaches.'),
('seed_005', 'eastwood-hills', 'Eastwood Hills', 'point', 'Neighborhoods', 'open', 'public', 'official', 'Farther east, closer to Blue River valley and Leeds-side access.'),
('seed_006', 'stayton-meadows', 'Stayton Meadows', 'point', 'Neighborhoods', 'open', 'public', 'official', 'East anchor for dropping into the Blue River and Leeds corridor.'),
('seed_007', 'south-indian-mound', 'South Indian Mound', 'point', 'Neighborhoods', 'open', 'public', 'official', 'Northeast stepping stone for Cliff Drive and Kessler access.'),
('seed_008', 'dunbar', 'Dunbar', 'point', 'Neighborhoods', 'open', 'public', 'official', 'Pairs with South Indian Mound as a northeast ladder back toward Brush Creek and the east side grid.'),
('seed_009', '53rd-raytown-area', '53rd & Raytown area', 'point', 'Ride anchors', 'open', 'public', 'official', 'Your home-zone anchor for heading south to Minor Park or north into the east-side grid.'),
('seed_010', 'blue-banks-park', 'Blue Banks Park', 'point', 'Ride anchors', 'open', 'public', 'official', 'Brush Creek meets Blue River here; a key handoff between east-west and north-south trail logic.'),
('seed_011', 'farewell-leeds-access', 'Farewell / Leeds access', 'point', 'Ride anchors', 'open', 'public', 'official', 'Mid-river access near Leeds and Municipal Farm ideas; more exploratory than polished.'),
('seed_012', 'minor-park-tennis-courts', 'Minor Park tennis courts', 'point', 'Ride anchors', 'open', 'public', 'official', 'South anchor for the paved Blue River Greenway and one of your cleanest trail access points.'),
('seed_013', 'cliff-drive-kessler', 'Cliff Drive / Kessler', 'point', 'Ride anchors', 'open', 'public', 'official', 'Classic northeast low-car corridor and a major loop ingredient.'),
('seed_014', 'rock-island-stadiums', 'Rock Island / Stadiums', 'point', 'Ride anchors', 'open', 'public', 'official', 'North terminus of the Rock Island Trail at the Truman Sports Complex (Lot L).'),
('seed_015', 'longview-trailhead-north-shelter-14', 'Longview Trailhead North (Shelter 14)', 'point', 'Ride anchors', 'open', 'public', 'official', 'Primary Longview Lake paved trail access at Shelter 14 on Longview Road.'),
('seed_016', 'longview-trailhead-south-odonnell-park-shelter-9', 'Longview Trailhead South (O''Donnell Park / Shelter 9)', 'point', 'Ride anchors', 'open', 'public', 'official', 'South end of the Longview Trail where it connects toward Grandview''s trail system.'),
('seed_017', 'exploration-off-road-note', 'Exploration / off-road note', 'point', 'Ride anchors', 'open', 'public', 'official', 'Mental reminder: levee, gravel, fence-gap, horse-trail, and rail-side cuts may be good when dry and terrible after weather.'),
('seed_018', 'gladstone-boundary', 'Gladstone boundary', 'point', 'Boundary anchors', 'open', 'public', 'official', 'North boundary anchor for your metro diamond.'),
('seed_019', 'blue-springs-boundary', 'Blue Springs boundary', 'point', 'Boundary anchors', 'open', 'public', 'official', 'East boundary anchor for your metro diamond.'),
('seed_020', 'grandview-boundary', 'Grandview boundary', 'point', 'Boundary anchors', 'open', 'public', 'official', 'South boundary anchor for your metro diamond.'),
('seed_021', 'overland-park-boundary', 'Overland Park boundary', 'point', 'Boundary anchors', 'open', 'public', 'official', 'West-southwest boundary anchor for your metro diamond.'),
('seed_022', 'fleming-park', 'Fleming Park', 'point', 'Key parks', 'open', 'public', 'official', 'Huge Jackson County park around Lake Jacomo and Blue Springs Lake with multiple trail systems.'),
('seed_023', 'longview-lake-park', 'Longview Lake Park', 'point', 'Key parks', 'open', 'public', 'official', 'Major south-metro park with the Longview Trail and connections toward Grandview.'),
('seed_024', 'minor-park', 'Minor Park', 'point', 'Key parks', 'open', 'public', 'official', 'South KC anchor where the Blue River Greenway becomes one of the cleanest paved trail options.'),
('seed_025', 'kessler-park', 'Kessler Park', 'point', 'Key parks', 'open', 'public', 'official', 'Major northeast bluff park tied to Cliff Drive and trail access above downtown.'),
('seed_026', 'sheffield-park', 'Sheffield Park', 'point', 'Key parks', 'open', 'public', 'official', 'East-side park near the stadium and Leeds corridor.'),
('seed_028', 'grand-blvd-bike-ped-bridge', 'Grand Blvd Bike & Ped Bridge', 'point', 'Ped bridges / sidewalks', 'open', 'public', 'official', 'New bike-and-ped bridge opened in May 2026 linking the river Market toward the riverfront.'),
('seed_029', 'oakley-ave-ped-bridge-replacement', 'Oakley Ave Ped Bridge Replacement', 'point', 'Planned / in progress', 'planned', 'public', 'planned', 'Pedestrian bridge over I-70 closed for replacement into 2026; worth watching in the field.'),
('seed_030', 'grand-lydia-riverfront-flyover-concept', 'Grand / Lydia riverfront flyover concept', 'point', 'Planned / in progress', 'planned', 'public', 'planned', 'Future connection concept linking surrounding neighborhoods toward the riverfront.'),
('seed_031', 'gillham-trolley-brush-creek-connector', 'Gillham-Trolley-Brush Creek connector', 'point', 'Planned / in progress', 'planned', 'public', 'planned', 'Protected connector work linking Gillham, Trolley Track, and Brush Creek corridors.'),
('seed_032', 'greenline-kc-segments', 'Greenline KC segments', 'point', 'Planned / in progress', 'planned', 'public', 'planned', 'Downtown Greenline loop sections projected to open in phases.'),
('seed_033', 'riverfront-streetcar-extension-corridor', 'Riverfront Streetcar Extension corridor', 'point', 'Planned / in progress', 'planned', 'public', 'planned', 'Mapped corridor from 3rd & Grand across the viaduct toward Berkley Riverfront.'),
('seed_034', 'blue-river-trails-project', 'Blue River Trails Project', 'point', 'Planned / in progress', 'planned', 'public', 'planned', 'KC Parks Blue River trail improvement process; a good corridor to watch.');
